		cliTag = version
	}

	actionRepo := "github/gh-aw/actions/setup-cli"
	if actionMode == ActionModeAction {
		actionRepo = "github/gh-aw-actions/setup-cli"
	}
	actionRef := fmt.Sprintf("%s@%s", actionRepo, cliTag)
	if pinnedRef, err := GetActionPinWithData(actionRepo, cliTag, data); err == nil && pinnedRef != "" {
